codeExample:
let a: null = null;
let b: undefined = undefined;

// Nullable types
let maybeString: string | null = null;
maybeString = "hello"; // OK

// Nullish coalescing
console.log(null ?? "fallback"); // "fallback"
console.log(0 ?? "fallback"); // 0 (0 is not nullish)
console.log(false ?? "fallback"); // false

// Optional chaining
const data: { value?: { name?: string } } = {};
const name: string | undefined = data?.value?.name;
